import java.util.Scanner;
import org.owasp.encoder.Encode;

public class SecureXSSDemo {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Encode user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        String greetingMessage = "Hello, " + encodedUserInput + "! Welcome to our website.";

        // Properly handling user input with encoding
        System.out.println("<div>" + greetingMessage + "</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
